import cv2
import numpy as np
import pickle
from flask import Flask, request, jsonify
from sklearn.svm import SVC
from sklearn.preprocessing import LabelEncoder
import os
from datetime import datetime

app = Flask(__name__)

class FacialRecognitionAPI:
    def __init__(self):
        self.model = SVC(kernel='rbf', probability=True)
        self.label_encoder = LabelEncoder()
        self.trained = False
        self.face_cascade = cv2.CascadeClassifier(cv2.data.haarcascades + 'haarcascade_frontalface_default.xml')
        
    def extract_faces(self, image_path):
        image = cv2.imread(image_path)
        gray = cv2.cvtColor(image, cv2.COLOR_BGR2GRAY)
        faces = self.face_cascade.detectMultiScale(gray, 1.3, 5)
        face_images = []
        for (x, y, w, h) in faces:
            face = gray[y:y+h, x:x+w]
            face = cv2.resize(face, (100, 100))
            face_images.append(face.flatten())
        return face_images
    
    def train_model(self, data_dir):
        faces = []
        labels = []
        
        for person_name in os.listdir(data_dir):
            person_dir = os.path.join(data_dir, person_name)
            if not os.path.isdir(person_dir):
                continue
                
            for image_file in os.listdir(person_dir):
                if image_file.lower().endswith(('.png', '.jpg', '.jpeg')):
                    image_path = os.path.join(person_dir, image_file)
                    face_features = self.extract_faces(image_path)
                    faces.extend(face_features)
                    labels.extend([person_name] * len(face_features))
        
        if len(faces) == 0:
            raise ValueError("No training data found")
            
        faces = np.array(faces)
        labels = np.array(labels)
        
        encoded_labels = self.label_encoder.fit_transform(labels)
        self.model.fit(faces, encoded_labels)
        self.trained = True
        
    def predict(self, image_path):
        if not self.trained:
            raise ValueError("Model not trained yet")
            
        face_features = self.extract_faces(image_path)
        if not face_features:
            return {"error": "No faces detected"}
            
        predictions = []
        for face in face_features:
            probabilities = self.model.predict_proba([face])[0]
            classes = self.label_encoder.classes_
            prediction = dict(zip(classes, probabilities))
            predictions.append(prediction)
            
        return predictions

# Initialize API
face_api = FacialRecognitionAPI()

@app.route('/train', methods=['POST'])
def train():
    try:
        data_dir = request.json.get('data_dir', 'employee_photos')
        face_api.train_model(data_dir)
        return jsonify({"status": "success", "message": "Model trained successfully"})
    except Exception as e:
        return jsonify({"status": "error", "message": str(e)}), 400

@app.route('/recognize', methods=['POST'])
def recognize():
    try:
        image_path = request.json.get('image_path')
        if not image_path:
            return jsonify({"error": "Image path required"}), 400
            
        results = face_api.predict(image_path)
        return jsonify({"predictions": results})
    except Exception as e:
        return jsonify({"error": str(e)}), 400

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)